import{_ as t,o,c as n,a3 as r}from"./chunks/framework.CjquFG0V.js";const y=JSON.parse('{"title":"26. Payment Of Wages Employee Records And Related Matters","description":"","frontmatter":{"title":"26. Payment Of Wages Employee Records And Related Matters","eba":"Nurses and Midwives 2024-2028","topics":["wages","preliminary"]},"headers":[],"relativePath":"ebas/nurses-midwives/wages/26-payment-of-wages-employee-records-and-related-matters.md","filePath":"ebas/nurses-midwives/wages/26-payment-of-wages-employee-records-and-related-matters.md"}'),s={name:"ebas/nurses-midwives/wages/26-payment-of-wages-employee-records-and-related-matters.md"};function a(i,e,p,l,m,h){return o(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="_26-payment-of-wages-employee-records-and-related-matters" tabindex="-1">26. Payment Of Wages Employee Records And Related Matters <a class="header-anchor" href="#_26-payment-of-wages-employee-records-and-related-matters" aria-label="Permalink to &quot;26. Payment Of Wages Employee Records And Related Matters&quot;">​</a></h1><p><strong>26.1</strong> Payment</p><p>Each Employee&#39;s wages will be paid fortnightly into the Employee&#39;s nominated account by electronic funds transfer, or other method determined by mutual agreement, on a weekday being not more than five days following the end of the pay period.</p><p><strong>26.2</strong> Employee Records</p><p><strong>(a)</strong> Payslip</p><p>The Act and FW Regulations set out an Employer&#39;s obligations with respect to pay slips, including but not limited to a requirement to specify:</p><p><strong>(i)</strong> the period to which the pay slip relates;</p><p><strong>(ii)</strong> the amount of wages to which the Employee is entitled;</p><p><strong>(iii)</strong> if an amount was deducted from the gross amount of the payment, the name or the name and number of the fund or account into which the deduction was paid; and</p><p><strong>(iv)</strong> the net amount for each payment.</p><p><strong>(b)</strong> To the extent reasonably practicable, payslips will record an Employee&#39;s accrued annual leave and personal leave.</p><p><strong>(c)</strong> Records</p><p>The Act and FW Regulations set out an Employer&#39;s obligations with respect to record keeping including but not limited to:</p><p><strong>(i)</strong> a requirement to keep a record that sets out any leave the Employee takes and the balance (if any) of the Employee&#39;s entitlement to that leave from time to time;</p><p><strong>(ii)</strong> the inspection and copying of an Employee record by the Employee or former Employee to whom the record relates; and</p><p><strong>(iii)</strong> the requirement to keep accurate Employee records.</p><p><strong>(d)</strong> Copying and Inspection of Record</p><p>After receiving a request from an Employee (or a former Employee) for a copy or inspection of their Employee record, the Employer must:</p><p><strong>(i)</strong> If the Employee record is kept at the premises at which the Employee works:</p><p><strong>(A)</strong> make the copy available to the Employee at the premises within 3 business days, or</p><p><strong>(B)</strong> post a copy to the Employee within 14 days after receiving the request, or</p><p><strong>(ii)</strong> If the Employee record is not kept at the premises at which the Employee works, as soon as practicable after receiving the request:</p><p><strong>(A)</strong> make the copy available to the Employee at the premises; or</p><p><strong>(B)</strong> post a copy of the Employee record to the Employee or former Employee.</p><p><strong>(e)</strong> For the purpose of this clause, an Employee record includes:</p><p><strong>(A)</strong> any documents or information prescribed by the Act or the FW Regulations;</p><p><strong>(B)</strong> any leave that the Employee takes; and</p><p><strong>(C)</strong> the balance (if any) of the Employee&#39;s entitlement to that leave from time to time.</p><p><strong>26.3</strong> Payment on termination</p><p><strong>(a)</strong> When an Employee&#39;s employment has been terminated by the Employer with notice, payment of all wages and other monies owing to an Employee will be made to the Employee on or before the final day of work of the Employee.</p><p><strong>(b)</strong> Where the Employer terminates the Employee&#39;s employment without notice, payment of all wages and other monies owing to the Employee will made to the Employee within two business days.</p><p><strong>(c)</strong> When notice of termination of employment has been given by an Employee, payment of all wages and other monies owing to an Employee will be made as soon as practicable but not later than the ordinary pay day following the end of employment.</p><p><strong>26.4</strong> Underpayment</p><p><strong>(a)</strong> Where an underpayment of wages occurs by reason of an error by the Employer involving 2.5% or more of the Employee&#39;s net weekly wage, the payment will be corrected by the end of the next business day at the request of the Employee save that:</p><p><strong>(i)</strong> except in cases of hardship, amounts less than 2.5% will be processed in the Employee&#39;s next pay period; and</p><p><strong>(ii)</strong> where the Employee notifies the Employer of hardship in respect of an amount owing less than 2.5%, the Employer will make its best endeavours to make the payment owing as soon as possible.</p><p><strong>(b)</strong> The Employer will notify the Employee of the adjustment being processed and provide the date of payment and any payment identification details.</p><p><strong>(c)</strong> This clause 26.4 will not apply where:</p><p><strong>(i)</strong> the Employer and Employee are in genuine dispute as to whether the monies are owed to the Employee;</p><p><strong>(ii)</strong> the underpayment is the result of an Employee error; or</p><p><strong>(iii)</strong> the reason for the underpayment is an unforeseen event or circumstance outside the control of the Employer, frustrating the Employer&#39;s ability to meet the requirements of this clause.</p><p><strong>26.5</strong> Unresolved Employee requests</p><p><strong>(a)</strong> Where the Employee has requested the correction of an underpayment as a result of an error as described at subclause 26.4(a) and, by the end of the next business day, the request is unresolved:</p><p><strong>(i)</strong> The Employee may notify a grievance in accordance with <a href="/eba/ebas/nurses-midwives/consultation-disputes/13-dispute-resolution-procedure.html">clause 13</a> of this Agreement, and:</p><p><strong>(A)</strong> Where a grievance is notified, the Employer will be available to meet with the Employee within two (2) business days and, if still unresolved, more senior managers will be available to meet with the Employee within a further two (2) business days; and</p><p><strong>(B)</strong> If unresolved after the steps at (A), above, or the Employer does not comply with (A) above, the grievance may be referred to the Commission and the requirements of clause</p><p><strong>13.4</strong> will be deemed to have been met.</p><p><strong>(b)</strong> The WIC will receive a report on the number of grievances arising from unresolved requests on a quarterly basis (or at a different frequency determined by the WIC).</p><p><strong>26.6</strong> Biometric Timekeeping</p><p>Where an Employer has or introduces biometric timekeeping, the Employer will give consideration to an Employee with genuine difficulties in complying with a requirement to utilise biometric technology to mitigate or avert the impact on that Employee.</p>',50)])])}const g=t(s,[["render",a]]);export{y as __pageData,g as default};
